#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float s = 0.01 + pow(q11, 2);     // should be < about 1
    vec2 nz = texture3D( sampler_noisevol_hq, vec3(vUvOriginal.xy*4*uTexSize.xy/850.0*s,uTime*0.1) );

    vec2 zz = vUvOriginal.xy * uTexSize.xy * 6 * 0.1 * s + nz*9;
    vUv.xy += vec2(cos(zz.y),cos(zz.x))*uTexSize.zw * 1.7 / s;

    // sample previous uFrame
    ret.xyz = texture( sampler_main, vUv ).xyz;

    ret.xyz *= 0.99;

      // add noise:
      vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1 + rand_frame.xy;
      ret.xyz += (texture(sampler_noise_lq, dither_uv).xyz-0.5)/256.0 * 122
                    //* clamp01(audioHighSmooth-1);
                    *0.16;

    // color rotate & desaturate over uTime, to keep the globs white
    ret.xyz = mix(ret.xyz, ret.zxy, 0.2);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float tim2 = uTime + 0.1;

    vec3 eye    = vec3(cos(uTime*0.1713), sin(uTime*0.1394), 0.1);
    vec3 lookat = vec3(cos(tim2*0.1713), sin(tim2*0.1394), 0);
    vec3 up = vec3(0,0,1);

    // Get a 3x3 orthonormal matrix for eye space.
    vec3 ez = normalize(lookat - eye);
    vec3 ex = normalize(cross(ez, eye));
    vec3 ey = -normalize(cross(ez, ex));

    // Use it to construct a crappy ray direction for this specific pixel.
    vec3 ray_dir = normalize(ez * 1 + ex * (vUv.x * 2 - 1) + ey * (vUv.y * 2 - 1));

    // What is the depth along the ray at which we intersect the ground plane?  (z==0)
    float t = -eye.z / ray_dir.z;
    vec3 ws = eye + t * ray_dir;
    vUv = ws.xy;

    ret = texture(sampler_main, vUv).xyz;
    ret = ret*1.5 - 0.1;

  fragColor = ret;
}
